# -*- coding: utf-8 -*-
"""Generate scripts/science_data/<l1>.json bank files for science bulk seeds.

Run once after editing; then run: python scripts/emit_science_bulk_seeds.py
"""
from __future__ import annotations

import json
from pathlib import Path
from typing import Any

ROOT = Path(__file__).resolve().parents[1]
OUT_DIR = ROOT / "scripts" / "science_data"

# Row: (question, correct, w1, w2, w3, explanation, kw1, kw2, source)


def R(
    q: str,
    ca: str,
    w: tuple[str, str, str],
    e: str,
    k1: str,
    k2: str,
    src: str,
) -> dict[str, Any]:
    return {
        "question": q,
        "correctAnswer": ca,
        "incorrectAnswers": list(w),
        "explanation": e,
        "keywords": [k1, k2],
        "source": src,
    }


def write_l1(name: str, bank: dict[str, list[dict[str, Any]]]) -> None:
    OUT_DIR.mkdir(parents=True, exist_ok=True)
    path = OUT_DIR / f"{name}.json"
    path.write_text(json.dumps(bank, ensure_ascii=True, indent=2) + "\n", encoding="utf-8")
    print("wrote", path)


